value.stringValue:
    trace.set_tracer_provider(provider)
    return provider


@contextmanager
def agent_span(name: str, model: str):
    tracer = trace.get_tracer("halo-claude-agents-demo")
    with tracer.start_as_current_span(
        name,
        attributes={
            "openinference.span.kind": "AGENT",
            "llm.model_name": model,
        },
    ) as span:
        yield span
